const platform = $input.first().json.platform || 'tiktok';
if (platform === 'tiktok') {
  const camp = $node['tiktok-split'].json;
  return [{ json: {...camp, platform: 'tiktok'} }];
} else {
  const camp = $node['linkedin-split'].json;
  return [{ json: {...camp, platform: 'linkedin'} }];
}

const camp = $node['identify-platform'].json;
const perf = $json;
const platform = camp.platform;

const spend = parseFloat(perf.spend || 0);
const clicks = parseInt(perf.clicks || 0);
const conversions = parseInt(perf.conversions || 0);
const convValue = parseFloat(perf.conversion_value || 0);
const ctr = parseFloat(perf.ctr || 0);
const engagementRate = parseFloat(perf.engagement_rate || 0);

const roas = spend > 0 ? convValue / spend : 0;
const cpa = conversions > 0 ? spend / conversions : null;
const cpc = clicks > 0 ? spend / clicks : null;

let platformMetrics = {};
let healthIssues = [];

if (platform === 'tiktok') {
  const hookRate = perf.hook_rate || 0;
  const completionRate = perf.completion_rate || 0;
  const isFatigued = hookRate < 0.3 || completionRate < 0.25;
  const isLowEngagement = engagementRate < 1.0;
  platformMetrics = { hook_rate: (hookRate * 100).toFixed(1) + '%', completion_rate: (completionRate * 100).toFixed(1) + '%', engagement_rate: (engagementRate * 100).toFixed(2) + '%' };
  if (isFatigued) healthIssues.push({type: 'creative_fatigue_tiktok', severity: 'high'});
  if (isLowEngagement) healthIssues.push({type: 'low_engagement', severity: 'medium'});
} else if (platform === 'linkedin') {
  const accountBased = perf.account_based_targeting === true;
  const matchedAudienceSize = perf.matched_audience_size || 0;
  const lowReach = matchedAudienceSize < 5000;
  platformMetrics = { account_based: accountBased, matched_audience: matchedAudienceSize };
  if (lowReach) healthIssues.push({type: 'low_matched_audience', severity: 'medium'});
}

return [{ json: {
  campaign_id: camp.id,
  campaign_name: camp.name,
  client_id: camp.client_id,
  platform,
  date: new Date().toISOString().slice(0, 10),
  spend: Math.round(spend * 100) / 100,
  conversions,
  conversion_value: Math.round(convValue * 100) / 100,
  roas: Math.round(roas * 100) / 100,
  cpa: cpa ? Math.round(cpa * 100) / 100 : null,
  cpc: cpc ? Math.round(cpc * 100) / 100 : null,
  ctr: Math.round(ctr * 1000) / 10,
  engagement_rate: (engagementRate * 100).toFixed(2) + '%',
  platform_metrics: platformMetrics,
  health_issues: healthIssues,
  is_healthy: healthIssues.length === 0
} }];

